from langchain_core.messages import AIMessage, ToolMessage
from langgraph.checkpoint.memory import MemorySaver

def make_mock_llm(tool_rounds: int):
    call_count = [0]
    def fake_invoke(messages):
        call_count[0] += 1
        if call_count[0] <= tool_rounds:
            return AIMessage(
                content="",
                tool_calls=[{"name": "search", "args": {"q": "test"}, "id": f"tc-{call_count[0]}"}],
            )
        return AIMessage(content="Final answer after tools.")
    return fake_invoke

def test_react_loop_terminates():
    mock = make_mock_llm(tool_rounds=2)
    # Patch the LLM inside the graph ...
    result = app.invoke({"messages": [{"role": "user", "content": "Test"}]})
    last = result["messages"][-1]
    assert isinstance(last, AIMessage)
    assert last.content == "Final answer after tools."
    # Exactly 2 tool rounds + 1 final call = 3 LLM calls
